/** 所有可用图标名称的排序列表（用于 IconPicker 遍历展示） */
export const ICON_NAMES: string[] = Object.keys(ICON_MAP).sort()

/**
 * 旧版图标名称 → lucide-react 名称的映射
 * 原因：Seed 数据中使用了小写简称（如 "setting", "permission"），
 * 需要兼容存量数据，避免数据库图标字段失效。
 */
const LEGACY_ICON_MAP: Record<string, string> = {
  setting: 'Settings',
  role: 'ShieldCheck',
  permission: 'Lock',
  department: 'Building2',
}

/**
 * 通过图标名称获取 lucide-react 组件
 * @param name 图标名称（如 "User", "Settings"），不区分大小写
 * @returns LucideIcon 组件，未找到时返回 null
 *
 * 示例：
 *   const Icon = getIcon('user')    // 返回 User 组件
 *   const Icon = getIcon('Settings') // 返回 Settings 组件
 */
export function getIcon(name?: string | null): LucideIcon | null {
  if (!name) return null
  // 先尝试精确匹配
  if (ICON_MAP[name]) return ICON_MAP[name]
  // 再尝试首字母大写匹配（兼容存储为小写的情况）
  const capitalized = name.charAt(0).toUpperCase() + name.slice(1)
  if (ICON_MAP[capitalized]) return ICON_MAP[capitalized]
  // 最后尝试旧版名称映射（兼容 seed 数据小写简称）
  const legacyName = LEGACY_ICON_MAP[name]
  if (legacyName && ICON_MAP[legacyName]) return ICON_MAP[legacyName]
  return null
}

/**
 * 动态图标渲染组件：根据名称渲染 lucide-react 图标
 * 用法：<DynamicIcon name="User" className="h-4 w-4" />
 */
export function DynamicIcon({ name, className, size }: { name?: string | null; className?: string; size?: number }) {
  const Icon = getIcon(name)
  if (!Icon) return null
  return <Icon className={className} size={size} />
}
